5	import EvalPage from "../eval/page";
6	import FoundersPage from "../founders/page";
7	import MethodsPage from "../methods/page";
8	import OpenQuestionsPage from "../open-questions/page";
9	import PeerReviewPage from "../peer-review/[conclusionId]/page";
10	import PostMortemPage from "../post-mortem/page";
11	import ProvenancePage from "../provenance/page";
12	import ReviewQueuePage from "../q/review/page";
13	import RigorGatePage from "../rigor-gate/page";
14	import RigorGateDetailPage from "../rigor-gate/[submissionId]/page";
15	import ScoreboardPage from "../scoreboard/page";
16	import TraceDrillDown from "@/components/TraceDrillDown";
17	import {
18	  getCostBurndown,
19	  getErrorSparkline,
20	  getMethodMetrics,
21	  getTrace,
22	  listInFlightTraces,
23	  listRecentAlerts,
24	  listRecentTraces,
25	} from "@/lib/opsApi";
26	
27	type OpsSearchParams = {
28	  panel?: string;
29	  target?: string;
30	  ledger?: string;
31	  asOf?: string;
32	  showResolved?: string;
33	  author?: string;
34	  engage?: string;
35	  domain?: string;
36	};
37	
38	const OPS_PANELS = [
39	  {
40	    id: "observability",
41	    label: "Observability",
42	    detail: "In-flight uploads, traces, error spikes, cost burndown.",
43	  },
44	  {
45	    id: "provenance",
46	    label: "Provenance",
47	    detail: "Extraction records and source chains.",
48	  },
49	  {
50	    id: "contradictions",
51	    label: "Contradictions",
52	    detail: "Claim pairs whose coherence layers disagree.",
53	  },
54	  {
55	    id: "peer-review",
56	    label: "Peer review",
57	    detail: "Per-conclusion review history, opened from a conclusion detail page.",
58	  },
59	  {
60	    id: "decay",
61	    label: "Decay",
62	    detail: "Confidence freshness and revalidation.",
63	  },
64	  {
65	    id: "rigor-gate",
66	    label: "Rigor gate",
67	    detail: "Mutation approvals, rejections, and overrides.",
68	  },
69	  {
70	    id: "methods",
71	    label: "Methods",
72	    detail: "Registered extraction and review methods.",
73	  },
74	] as const;
75	
76	export default async function OpsPage({
77	  searchParams,
78	}: {
79	  searchParams: Promise<OpsSearchParams>;
80	}) {
81	  const sp = await searchParams;
82	  const panel = sp.panel || "overview";
83	  const target = firstPathSegment(sp.target);
84	
85	  if (panel === "provenance") return <ProvenancePage />;
86	  if (panel === "eval") return <EvalPage />;
87	  if (panel === "contradictions") {
88	    return (
89	      <ContradictionsPage
90	        searchParams={Promise.resolve({
91	          asOf: sp.asOf,
92	          showResolved: sp.showResolved,
93	        })}
94	      />
95	    );
96	  }
97	  if (panel === "peer-review") {
98	    if (!target) return <PeerReviewIndex />;
99	    return (
100	      <PeerReviewPage
101	        params={Promise.resolve({ conclusionId: target })}
102	        searchParams={Promise.resolve({ ledger: sp.ledger })}
103	      />
104	    );
105	  }
106	  if (panel === "open-questions") {
107	    return <OpenQuestionsPage searchParams={Promise.resolve({ domain: sp.domain })} />;
108	  }
109	  if (panel === "adversarial") return <AdversarialPage />;
110	  if (panel === "layer-review") return <ReviewQueuePage />;
111	  if (panel === "calibration") {
112	    return (
113	      <ScoreboardPage
114	        searchParams={Promise.resolve({
115	          author: sp.author,
116	          engage: sp.engage,
117	        })}
118	      />
119	    );
120	  }
121	  if (panel === "post-mortem") return <PostMortemPage />;
122	  if (panel === "decay") {
123	    return <DecayPage searchParams={Promise.resolve({ ledger: sp.ledger })} />;
124	  }
125	  if (panel === "rigor-gate") {
126	    if (target) {
127	      return (
128	        <RigorGateDetailPage
129	          params={Promise.resolve({ submissionId: target })}
130	          searchParams={Promise.resolve({ ledger: sp.ledger })}
131	        />
132	      );
133	    }
134	    return <RigorGatePage searchParams={Promise.resolve({ ledger: sp.ledger })} />;
135	  }
136	  if (panel === "methods") return <MethodsPage />;
137	  if (panel === "observability") {
138	    if (target) {
139	      return <ObservabilityTracePanel traceId={target} />;
140	    }
141	    return <ObservabilityPanel />;
142	  }
143	  if (panel === "founders") {
144	    return <FoundersPage searchParams={Promise.resolve({ asOf: sp.asOf })} />;
145	  }
146	
147	  return <OpsOverview />;
148	}
149	
150	function firstPathSegment(value: string | undefined): string {
151	  return (value || "").split("/").filter(Boolean)[0] || "";
152	}
153	
154	function OpsOverview() {
155	  return (
156	    <main style={{ maxWidth: "1040px", margin: "0 auto", padding: "3rem 2rem" }}>
157	      <header style={{ marginBottom: "1.75rem" }}>
158	        <h1
159	          style={{
160	            fontFamily: "'Cinzel Decorative', 'Cinzel', serif",
161	            fontSize: "1.8rem",
162	            letterSpacing: "0.16em",
163	            color: "var(--amber)",
164	            margin: 0,
165	            textShadow: "var(--glow-sm)",
166	          }}
167	        >
168	          Ops
169	        </h1>
170	        <p
171	          className="mono"
172	          style={{
173	            color: "var(--amber-dim)",
174	            fontSize: "0.62rem",
175	            letterSpacing: "0.24em",
176	            textTransform: "uppercase",
177	          }}
178	        >
179	          Advanced tooling · Audit surfaces · Founder operations
180	        </p>
181	      </header>
182	
183	      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(220px, 1fr))", gap: "0.85rem" }}>
184	        {OPS_PANELS.map((panel) => (
185	          <Link
186	            key={panel.id}
187	            href={`/ops?panel=${panel.id}`}
188	            className="portal-card"
189	            style={{
