191	              display: "block",
192	              padding: "1rem 1.1rem",
193	              textDecoration: "none",
194	            }}
195	          >
196	            <h2
197	              style={{
198	                color: "var(--gold)",
199	                fontFamily: "'Cinzel', serif",
200	                fontSize: "0.9rem",
201	                letterSpacing: "0.1em",
202	                margin: 0,
203	              }}
204	            >
205	              {panel.label}
206	            </h2>
207	            <p style={{ color: "var(--parchment-dim)", fontSize: "0.85rem", lineHeight: 1.5, margin: "0.5rem 0 0" }}>
208	              {panel.detail}
209	            </p>
210	          </Link>
211	        ))}
212	      </div>
213	    </main>
