216	
217	function PeerReviewIndex() {
218	  return (
219	    <main style={{ maxWidth: "840px", margin: "0 auto", padding: "3rem 2rem" }}>
220	      <h1
221	        style={{
222	          fontFamily: "'Cinzel', serif",
223	          color: "var(--gold)",
224	          letterSpacing: "0.08em",
225	        }}
226	      >
227	        Peer review
228	      </h1>
229	      <div className="portal-card" style={{ padding: "1rem 1.25rem", color: "var(--parchment-dim)", lineHeight: 1.6 }}>
230	        Peer review is now opened from an individual conclusion. Go to{" "}
231	        <Link href="/knowledge?tab=conclusions" style={{ color: "var(--gold)" }}>
232	          Knowledge
233	        </Link>
234	        , choose a conclusion, then use its peer review tab or action bar.
235	      </div>
236	    </main>
237	  );
238	}
239	
240	function fmtMs(ms: number | null): string {
241	  if (ms === null || ms === undefined) return "—";
242	  if (ms < 1000) return `${ms.toFixed(0)} ms`;
243	  return `${(ms / 1000).toFixed(2)} s`;
244	}
245	
246	async function ObservabilityPanel() {
247	  const [inFlight, recent, methodMetrics, alerts, burndown, sparkline] =
248	    await Promise.all([
249	      listInFlightTraces(),
250	      listRecentTraces(20),
251	      getMethodMetrics({ sinceDays: 7 }),
252	      listRecentAlerts(10),
253	      getCostBurndown(),
254	      getErrorSparkline(24),
255	    ]);
256	
257	  const burnPct = Math.min(
258	    100,
259	    (burndown.spentUsd / Math.max(0.01, burndown.budgetUsd)) * 100,
260	  );
261	  const sparkMax = Math.max(1, ...sparkline.map((s) => s.total));
262	
263	  return (
264	    <main style={{ maxWidth: "1200px", margin: "0 auto", padding: "2.5rem 1.5rem" }}>
265	      <header style={{ marginBottom: "1.5rem" }}>
266	        <h1
267	          style={{
268	            fontFamily: "'Cinzel Decorative', 'Cinzel', serif",
269	            fontSize: "1.6rem",
270	            letterSpacing: "0.16em",
271	            color: "var(--amber)",
272	            margin: 0,
273	          }}
274	        >
275	          Observability
276	        </h1>
277	        <p
278	          className="mono"
279	          style={{
280	            color: "var(--amber-dim)",
281	            fontSize: "0.6rem",
282	            letterSpacing: "0.24em",
283	            textTransform: "uppercase",
284	          }}
285	        >
286	          Pipeline traces · Method latency · Cost burndown
287	        </p>
288	      </header>
289	
290	      <section
291	        style={{
292	          display: "grid",
293	          gridTemplateColumns: "repeat(auto-fit, minmax(220px, 1fr))",
294	          gap: "0.75rem",
295	          marginBottom: "1.5rem",
296	        }}
297	      >
298	        <div className="portal-card" style={{ padding: "0.9rem 1rem" }}>
299	          <div className="mono" style={{ color: "var(--amber-dim)", fontSize: "0.6rem", letterSpacing: "0.18em" }}>
300	            IN FLIGHT
301	          </div>
302	          <div style={{ fontSize: "1.6rem", color: "var(--gold)" }}>{inFlight.length}</div>
303	          <div style={{ fontSize: "0.75rem", color: "var(--parchment-dim)" }}>active uploads</div>
304	        </div>
305	        <div className="portal-card" style={{ padding: "0.9rem 1rem" }}>
306	          <div className="mono" style={{ color: "var(--amber-dim)", fontSize: "0.6rem", letterSpacing: "0.18em" }}>
307	            ALERTS · 24H
308	          </div>
309	          <div style={{ fontSize: "1.6rem", color: "var(--gold)" }}>{alerts.length}</div>
310	          <div style={{ fontSize: "0.75rem", color: "var(--parchment-dim)" }}>recent firings</div>
311	        </div>
312	        <div className="portal-card" style={{ padding: "0.9rem 1rem" }}>
313	          <div className="mono" style={{ color: "var(--amber-dim)", fontSize: "0.6rem", letterSpacing: "0.18em" }}>
314	            COST · 24H
315	          </div>
316	          <div style={{ fontSize: "1.6rem", color: "var(--gold)" }}>
317	            ${burndown.spentUsd.toFixed(2)}
318	          </div>
319	          <div
320	            style={{
321	              marginTop: "0.4rem",
322	              height: "6px",
323	              background: "rgba(0,0,0,0.3)",
324	              borderRadius: "3px",
325	              overflow: "hidden",
326	            }}
327	          >
328	            <div
329	              style={{
330	                height: "100%",
331	                width: `${burnPct}%`,
332	                background: burnPct > 80 ? "var(--ember, #cc4a3a)" : "var(--gold)",
333	              }}
334	            />
335	          </div>
336	          <div style={{ fontSize: "0.7rem", color: "var(--parchment-dim)", marginTop: "0.2rem" }}>
337	            of ${burndown.budgetUsd.toFixed(2)} budget
338	          </div>
339	        </div>
340	      </section>
341	
342	      <section style={{ marginBottom: "1.5rem" }}>
343	        <h2 style={{ fontFamily: "'Cinzel', serif", fontSize: "0.95rem", color: "var(--gold)", letterSpacing: "0.1em" }}>
344	          Error sparkline (24h)
345	        </h2>
346	        <div className="portal-card" style={{ padding: "0.75rem", display: "flex", alignItems: "flex-end", gap: "2px", height: "60px" }}>
347	          {sparkline.map((s, i) => {
348	            const heightPct = (s.total / sparkMax) * 100;
349	            const errorPct = s.total === 0 ? 0 : (s.errorCount / s.total) * 100;
350	            return (
351	              <div
352	                key={i}
353	                title={`${s.hour.toLocaleTimeString()}: ${s.errorCount}/${s.total} errors`}
354	                style={{ flex: 1, height: `${heightPct}%`, position: "relative", background: "rgba(200,166,74,0.25)" }}
355	              >
356	                <div
357	                  style={{
358	                    position: "absolute",
359	                    bottom: 0,
360	                    left: 0,
361	                    right: 0,
362	                    height: `${errorPct}%`,
363	                    background: "var(--ember, #cc4a3a)",
364	                  }}
365	                />
366	              </div>
367	            );
368	          })}
369	        </div>
370	      </section>
371	
372	      <section style={{ marginBottom: "1.5rem" }}>
373	        <h2 style={{ fontFamily: "'Cinzel', serif", fontSize: "0.95rem", color: "var(--gold)", letterSpacing: "0.1em" }}>
374	          Recent traces
375	        </h2>
376	        <div className="portal-card" style={{ padding: "0.75rem", overflowX: "auto" }}>
377	          <table style={{ width: "100%", borderCollapse: "collapse", fontSize: "0.82rem" }}>
378	            <thead>
379	              <tr style={{ textAlign: "left", color: "var(--parchment-dim)" }}>
380	                <th>Started</th>
381	                <th>Root</th>
382	                <th>Spans</th>
383	                <th>Status</th>
384	                <th>Duration</th>
385	                <th></th>
386	              </tr>
387	            </thead>
388	            <tbody>
389	              {recent.map((t) => (
390	                <tr key={t.traceId} style={{ borderTop: "1px solid var(--rule, rgba(200,166,74,0.15))" }}>
391	                  <td className="mono" style={{ fontSize: "0.72rem", color: "var(--parchment-dim)" }}>
392	                    {t.startedAt.toISOString().replace("T", " ").slice(0, 19)}
393	                  </td>
394	                  <td>{t.rootName}</td>
395	                  <td>
396	                    {t.spanCount}
397	                    {t.errorCount > 0 ? <span style={{ color: "var(--ember, #cc4a3a)" }}> · {t.errorCount} err</span> : null}
398	                  </td>
399	                  <td>
400	                    <span
401	                      style={{
402	                        color:
403	                          t.status === "error"
404	                            ? "var(--ember, #cc4a3a)"
405	                            : t.status === "in_flight"
406	                              ? "var(--amber)"
407	                              : "var(--gold)",
408	                      }}
409	                    >
410	                      {t.status}
411	                    </span>
412	                  </td>
413	                  <td>{fmtMs(t.durationMs)}</td>
414	                  <td>
415	                    <Link
416	                      href={`/ops?panel=observability&target=${t.traceId}`}
417	                      style={{ color: "var(--gold)" }}
418	                    >
419	                      drill in →
420	                    </Link>
421	                  </td>
422	                </tr>
423	              ))}
424	              {recent.length === 0 && (
425	                <tr>
426	                  <td colSpan={6} style={{ color: "var(--parchment-dim)", padding: "0.5rem" }}>
427	                    No traces yet. Run an ingest to see one here.
428	                  </td>
429	                </tr>
430	              )}
431	            </tbody>
432	          </table>
433	        </div>
434	      </section>
435	
436	      <section style={{ marginBottom: "1.5rem" }}>
437	        <h2 style={{ fontFamily: "'Cinzel', serif", fontSize: "0.95rem", color: "var(--gold)", letterSpacing: "0.1em" }}>
438	          Method latency · last 7 days
439	        </h2>
440	        <div className="portal-card" style={{ padding: "0.75rem", overflowX: "auto" }}>
441	          <table style={{ width: "100%", borderCollapse: "collapse", fontSize: "0.82rem" }}>
442	            <thead>
443	              <tr style={{ textAlign: "left", color: "var(--parchment-dim)" }}>
444	                <th>Method</th>
445	                <th>Calls</th>
446	                <th>p50</th>
447	                <th>p95</th>
448	                <th>Errors</th>
449	                <th>Cost</th>
450	              </tr>
451	            </thead>
452	            <tbody>
453	              {methodMetrics.map((m, i) => (
454	                <tr key={`${m.method}-${i}`} style={{ borderTop: "1px solid var(--rule, rgba(200,166,74,0.15))" }}>
455	                  <td>{m.method}</td>
456	                  <td>{m.count}</td>
457	                  <td>{fmtMs(m.p50Ms)}</td>
458	                  <td>{fmtMs(m.p95Ms)}</td>
459	                  <td style={{ color: m.errorRate > 0.05 ? "var(--ember, #cc4a3a)" : undefined }}>
460	                    {(m.errorRate * 100).toFixed(1)}%
461	                  </td>
462	                  <td>${m.costUsd.toFixed(3)}</td>
463	                </tr>
464	              ))}
465	              {methodMetrics.length === 0 && (
466	                <tr>
467	                  <td colSpan={6} style={{ color: "var(--parchment-dim)", padding: "0.5rem" }}>
468	                    No rollups yet. The nightly job populates this table.
469	                  </td>
470	                </tr>
471	              )}
472	            </tbody>
473	          </table>
474	        </div>
475	      </section>
476	
477	      {alerts.length > 0 && (
478	        <section>
479	          <h2 style={{ fontFamily: "'Cinzel', serif", fontSize: "0.95rem", color: "var(--gold)", letterSpacing: "0.1em" }}>
480	            Recent alerts
481	          </h2>
482	          <div className="portal-card" style={{ padding: "0.75rem" }}>
483	            {alerts.map((a) => (
484	              <div
485	                key={a.id}
486	                style={{
487	                  display: "flex",
488	                  justifyContent: "space-between",
