513	async function ObservabilityTracePanel({ traceId }: { traceId: string }) {
514	  const spans = await getTrace(traceId);
515	  return (
516	    <main style={{ maxWidth: "1100px", margin: "0 auto", padding: "2.5rem 1.5rem" }}>
517	      <div style={{ marginBottom: "1rem" }}>
