1	/**
2	 * Manual "Process now" endpoint.
3	 *
4	 * Given an `upload_id`, fires the same GitHub Actions webhook that
5	 * `/api/upload` fires automatically. Useful when:
6	 *
7	 *   * the auto-dispatch failed silently and the user wants to retry
8	 *     without waiting for the 10-minute cron;
9	 *   * the upload came in via API before the dispatch wiring existed
10	 *     (legacy rows in `queued_offline` state);
11	 *   * the user wants to re-run an upload in `--with-llm` mode after
12	 *     the naive pass already marked it `ingested`.
13	 *
14	 * Authentication follows the same pattern as the rest of the API:
15	 * session cookie OR `Authorization: Bearer tcx_...` API key. The
16	 * caller must belong to the same organization as the upload.
17	 */
18	import { NextResponse } from "next/server";
19	import { getFounderFromAuth } from "@/lib/apiKeyAuth";
20	import { db } from "@/lib/db";
21	import { canWrite, WRITE_FORBIDDEN_RESPONSE } from "@/lib/roles";
22	import { sanitizeAndCap } from "@/lib/sanitizeText";
23	import { triggerNoosphereProcessing } from "@/lib/triggerNoosphereProcessing";
24	
25	export async function POST(req: Request) {
26	  try {
27	    const founder = await getFounderFromAuth(req);
28	    if (!founder) {
29	      return NextResponse.json(
30	        { error: "Not authenticated" },
31	        { status: 401 },
32	      );
33	    }
34	    // Re-triggering processing re-runs Noosphere extraction, which
35	    // writes Conclusion / Contradiction / OpenQuestion rows. Treating
36	    // it as a write keeps the rule simple — if you can't upload, you
37	    // can't re-process. Admins can re-trigger on behalf of viewers
38	    // if needed.
39	    if (!canWrite(founder.role)) {
40	      return NextResponse.json(WRITE_FORBIDDEN_RESPONSE, { status: 403 });
41	    }
42	
43	    const body = (await req.json().catch(() => ({}))) as {
44	      upload_id?: string;
45	      uploadId?: string;
46	      with_llm?: boolean;
47	      withLlm?: boolean;
48	    };
49	    const uploadId = body.upload_id || body.uploadId;
50	    if (!uploadId) {
51	      return NextResponse.json(
52	        { error: "upload_id is required" },
53	        { status: 400 },
54	      );
55	    }
56	
57	    // Confirm the upload belongs to the caller's org before triggering.
58	    // Otherwise this would let any authed user re-run any org's
59	    // uploads — cheap, but it'd mess up other firms' ingest logs.
60	    const upload = await db.upload.findUnique({
61	      where: { id: uploadId },
62	      select: {
63	        id: true,
64	        organizationId: true,
65	        founderId: true,
66	        status: true,
67	        title: true,
68	        textContent: true,
69	        deletedAt: true,
70	        visibility: true,
71	      },
72	    });
73	    if (!upload) {
74	      return NextResponse.json({ error: "Upload not found" }, { status: 404 });
75	    }
76	    if (upload.organizationId !== founder.organizationId) {
77	      return NextResponse.json({ error: "Forbidden" }, { status: 403 });
78	    }
79	    // Private uploads: only the owner can retrigger processing. A peer
80	    // getting the id (say, via a leaked process log) shouldn't be able
81	    // to poke the pipeline and leak timing/status information. 404
82	    // rather than 403 so existence isn't confirmed.
83	    if (upload.visibility === "private" && upload.founderId !== founder.id) {
84	      return NextResponse.json({ error: "Upload not found" }, { status: 404 });
85	    }
86	    if (upload.deletedAt) {
87	      return NextResponse.json(
88	        {
89	          error:
90	            "This upload has been deleted. Processing cannot be re-triggered.",
91	        },
92	        { status: 410 },
93	      );
94	    }
95	
96	    // A bare upload with no extracted text has nothing Noosphere can do
97	    // with it. Signal this explicitly rather than silently queuing.
98	    if (!upload.textContent || upload.textContent.trim().length < 40) {
99	      return NextResponse.json(
100	        {
101	          error:
102	            "Upload has no extractable text content. Re-upload a text/PDF/DOCX " +
103	            "version, or set OPENAI_API_KEY so audio can be transcribed.",
104	        },
105	        { status: 422 },
106	      );
107	    }
108	
109	    const withLlm = Boolean(body.with_llm ?? body.withLlm ?? true);
110	    const result = await triggerNoosphereProcessing(uploadId, {
111	      organizationId: founder.organizationId,
112	      withLlm,
113	    });
114	
115	    // Annotate the upload row so the UI can show progress. Every
116	    // string headed to Postgres is scrubbed of NUL bytes and capped
117	    // so an unexpected note payload can't blow the insert.
118	    try {
