1	import { db } from "@/lib/db";
2	
3	/**
4	 * Read API for the operator dashboard.
5	 *
6	 * The Python pipeline writes spans to Postgres (table `Span`) under a
7	 * shared `traceId`; the nightly rollup populates `MethodMetricRollup`
8	 * so trendlines stay queryable past span retention. This file is the
9	 * only place the dashboard talks to those tables — keep aggregations
10	 * here so the page can stay a thin renderer.
11	 */
12	
13	export type SpanRow = {
14	  id: string;
15	  traceId: string;
16	  parentSpanId: string | null;
17	  name: string;
18	  status: string;
19	  startedAt: Date;
20	  endedAt: Date | null;
21	  durationMs: number | null;
22	  errorKind: string | null;
23	  errorMessage: string | null;
24	  attrs: Record<string, unknown>;
25	  costUsd: number;
26	};
27	
28	export type TraceSummary = {
29	  traceId: string;
30	  startedAt: Date;
31	  endedAt: Date | null;
32	  durationMs: number | null;
33	  spanCount: number;
34	  errorCount: number;
35	  rootName: string;
36	  status: "ok" | "error" | "in_flight";
37	};
38	
39	export type MethodMetricRow = {
40	  method: string;
41	  count: number;
42	  errorCount: number;
43	  errorRate: number;
44	  p50Ms: number;
45	  p95Ms: number;
46	  costUsd: number;
47	  windowStart: Date;
48	  windowEnd: Date;
49	};
50	
51	export type AlertEventRow = {
52	  id: string;
53	  ruleName: string;
54	  method: string;
55	  metric: string;
56	  value: number;
57	  threshold: number;
58	  firedAt: Date;
59	  acknowledgedAt: Date | null;
60	};
61	
62	export type CostBudget = {
63	  spentUsd: number;
64	  budgetUsd: number;
65	  windowStart: Date;
66	  windowEnd: Date;
67	};
68	
69	const DEFAULT_TRACE_LIMIT = 25;
70	
71	function toRecord(value: unknown): Record<string, unknown> {
72	  if (value && typeof value === "object" && !Array.isArray(value)) {
73	    return value as Record<string, unknown>;
74	  }
75	  return {};
76	}
77	
78	function spanFromDb(row: {
79	  id: string;
80	  traceId: string;
81	  parentSpanId: string | null;
82	  name: string;
83	  status: string;
84	  startedAt: Date;
85	  endedAt: Date | null;
86	  durationMs: number | null;
87	  errorKind: string | null;
88	  errorMessage: string | null;
89	  attrs: unknown;
90	  costUsd: number;
91	}): SpanRow {
92	  return {
93	    id: row.id,
94	    traceId: row.traceId,
95	    parentSpanId: row.parentSpanId,
96	    name: row.name,
97	    status: row.status,
98	    startedAt: row.startedAt,
99	    endedAt: row.endedAt,
100	    durationMs: row.durationMs,
101	    errorKind: row.errorKind,
102	    errorMessage: row.errorMessage,
103	    attrs: toRecord(row.attrs),
104	    costUsd: row.costUsd,
105	  };
106	}
107	
108	/**
109	 * Recent traces, newest first. A trace is in_flight if any span is open
110	 * (no `endedAt`) — the dashboard surfaces these prominently during a
111	 * publish-day surge.
112	 */
113	export async function listRecentTraces(
114	  limit = DEFAULT_TRACE_LIMIT,
115	): Promise<TraceSummary[]> {
116	  const rows = await db.span.findMany({
117	    orderBy: { startedAt: "desc" },
118	    take: limit * 12, // overshoot, then group by trace
119	  });
120	
121	  const byTrace = new Map<string, SpanRow[]>();
122	  for (const row of rows) {
123	    const span = spanFromDb(row);
124	    const list = byTrace.get(span.traceId) ?? [];
125	    list.push(span);
126	    byTrace.set(span.traceId, list);
127	  }
128	
129	  const summaries: TraceSummary[] = [];
130	  for (const [traceId, spans] of byTrace) {
131	    spans.sort((a, b) => a.startedAt.getTime() - b.startedAt.getTime());
132	    const root = spans.find((s) => s.parentSpanId === null) ?? spans[0];
133	    const allClosed = spans.every((s) => s.endedAt !== null);
134	    const lastEnd = allClosed
135	      ? new Date(
136	          Math.max(...spans.map((s) => (s.endedAt as Date).getTime())),
137	        )
138	      : null;
139	    const errorCount = spans.filter((s) => s.status === "error").length;
140	    summaries.push({
141	      traceId,
142	      startedAt: root.startedAt,
143	      endedAt: lastEnd,
144	      durationMs:
145	        lastEnd === null ? null : lastEnd.getTime() - root.startedAt.getTime(),
146	      spanCount: spans.length,
147	      errorCount,
148	      rootName: root.name,
149	      status: !allClosed ? "in_flight" : errorCount > 0 ? "error" : "ok",
150	    });
151	  }
152	  summaries.sort((a, b) => b.startedAt.getTime() - a.startedAt.getTime());
153	  return summaries.slice(0, limit);
154	}
155	
156	export async function listInFlightTraces(): Promise<TraceSummary[]> {
157	  const all = await listRecentTraces(100);
158	  return all.filter((t) => t.status === "in_flight");
159	}
160	
161	export async function getTrace(traceId: string): Promise<SpanRow[]> {
162	  const rows = await db.span.findMany({
163	    where: { traceId },
164	    orderBy: { startedAt: "asc" },
165	  });
166	  return rows.map(spanFromDb);
167	}
168	
169	export async function getMethodMetrics(
170	  options: { sinceDays?: number } = {},
171	): Promise<MethodMetricRow[]> {
172	  const sinceDays = options.sinceDays ?? 7;
173	  const since = new Date(Date.now() - sinceDays * 24 * 60 * 60 * 1000);
174	  const rows = await db.methodMetricRollup.findMany({
175	    where: { windowStart: { gte: since } },
176	    orderBy: { windowStart: "desc" },
177	  });
178	  return rows.map((r) => ({
179	    method: r.method,
180	    count: r.count,
181	    errorCount: r.errorCount,
182	    errorRate: r.errorRate,
183	    p50Ms: r.p50Ms,
184	    p95Ms: r.p95Ms,
185	    costUsd: r.costUsd,
186	    windowStart: r.windowStart,
187	    windowEnd: r.windowEnd,
188	  }));
189	}
190	
191	export async function listRecentAlerts(limit = 25): Promise<AlertEventRow[]> {
192	  const rows = await db.alertEvent.findMany({
193	    orderBy: { firedAt: "desc" },
194	    take: limit,
195	  });
196	  return rows.map((r) => ({
197	    id: r.id,
198	    ruleName: r.ruleName,
199	    method: r.method,
200	    metric: r.metric,
201	    value: r.value,
202	    threshold: r.threshold,
203	    firedAt: r.firedAt,
204	    acknowledgedAt: r.acknowledgedAt,
205	  }));
206	}
207	
208	/**
209	 * Cost spent in the trailing 24h vs daily budget. Read from env until
210	 * a per-tenant budget surface lands.
211	 */
212	export async function getCostBurndown(): Promise<CostBudget> {
213	  const since = new Date(Date.now() - 24 * 60 * 60 * 1000);
214	  const aggregate = await db.span.aggregate({
215	    where: { startedAt: { gte: since } },
216	    _sum: { costUsd: true },
217	  });
218	  const spent = aggregate._sum.costUsd ?? 0;
219	  const budget = Number(process.env.NOOSPHERE_DAILY_BUDGET_USD ?? "50") || 50;
220	  return {
221	    spentUsd: spent,
222	    budgetUsd: budget,
223	    windowStart: since,
224	    windowEnd: new Date(),
225	  };
226	}
227	
228	/**
229	 * Number of error spans bucketed by hour over the trailing window.
230	 * Powers the "error spikes" sparkline.
231	 */
232	export async function getErrorSparkline(
233	  hours = 24,
234	): Promise<Array<{ hour: Date; errorCount: number; total: number }>> {
235	  const since = new Date(Date.now() - hours * 60 * 60 * 1000);
236	  const rows = await db.span.findMany({
237	    where: { startedAt: { gte: since } },
238	    select: { startedAt: true, status: true },
239	  });
240	  const buckets = new Map<number, { errorCount: number; total: number }>();
241	  for (const r of rows) {
242	    const hourStart = new Date(r.startedAt);
243	    hourStart.setMinutes(0, 0, 0);
244	    const key = hourStart.getTime();
245	    const slot = buckets.get(key) ?? { errorCount: 0, total: 0 };
246	    slot.total += 1;
247	    if (r.status === "error") slot.errorCount += 1;
248	    buckets.set(key, slot);
249	  }
250	  const out: Array<{ hour: Date; errorCount: number; total: number }> = [];
251	  for (let i = hours - 1; i >= 0; i--) {
252	    const hour = new Date(Date.now() - i * 60 * 60 * 1000);
253	    hour.setMinutes(0, 0, 0);
254	    const slot = buckets.get(hour.getTime()) ?? { errorCount: 0, total: 0 };
255	    out.push({ hour, errorCount: slot.errorCount, total: slot.total });
256	  }
257	  return out;
258	}
