1	import { randomUUID } from "crypto";
2	
3	import type {
4	  PublicFollowupMessage,
5	  PublicOpinion,
6	  PublicReconciliation,
7	  PublicReconciliationCounter,
8	  PublicSource,
9	  PublicCitation,
10	} from "@/lib/currentsTypes";
11	import { clientIpFor } from "@/lib/currentsFingerprint";
12	
13	export const BACKEND = (process.env.CURRENTS_API_URL ?? "http://127.0.0.1:8088").replace(/\/+$/, "");
14	
15	export interface ListCurrentsParams {
16	  since?: string | Date | null;
17	  until?: string | Date | null;
18	  topic?: string | null;
19	  stance?: string | null;
20	  limit?: number | null;
21	  seeded?: boolean | null;
22	}
23	
24	export interface CurrentsLastCycle {
25	  started_at: string | null;
26	  duration_ms: number;
27	  ingested: number;
28	  opined: number;
29	  rejected: number;
30	  abstained_insufficient: number;
31	  abstained_below_significance: number;
32	  abstained_off_domain: number;
33	  abstained_near_duplicate: number;
34	  abstained_budget: number;
35	  error_count: number;
36	  last_error: string | null;
37	}
38	
39	export interface CurrentsHealth {
40	  x_bearer_present: boolean;
41	  curated_count: number;
42	  search_count: number;
43	  last_cycle_at: string | null;
44	  last_event_at?: string | null;
45	  last_opinion_at?: string | null;
46	  events_last_24h: number;
47	  opinions_last_24h: number;
48	  disabled_reasons: string[];
49	  last_cycle?: CurrentsLastCycle | null;
50	}
51	
52	type StreamingRequestInit = RequestInit & { duplex?: "half" };
53	type NextFetchOptions = {
54	  revalidate?: number | false;
55	  tags?: string[];
56	};
57	
58	export interface CurrentsFetchOptions {
59	  cache?: RequestCache;
60	  next?: NextFetchOptions;
61	  signal?: AbortSignal;
62	}
63	
64	type NextRequestInit = RequestInit & { next?: NextFetchOptions };
65	
66	type CitationWire = PublicCitation & {
67	  conclusion_text?: string | null;
68	  conclusionText?: string | null;
69	  conclusion_title?: string | null;
70	  conclusionTitle?: string | null;
71	  public_url?: string | null;
72	  publicUrl?: string | null;
73	  source_text?: string | null;
74	  source_visibility?: string | null;
75	  visibility?: string | null;
76	};
77	
78	type SourceWire = PublicSource & {
79	  conclusion_text?: string | null;
80	  conclusionText?: string | null;
81	  conclusion_title?: string | null;
82	  conclusionTitle?: string | null;
83	  public_url?: string | null;
84	  publicUrl?: string | null;
85	  source_visibility?: string | null;
86	  visibility?: string | null;
87	};
88	
89	interface CitationMetadata {
90	  conclusionText?: string | null;
91	  conclusionTitle?: string | null;
92	  publicUrl?: string | null;
93	  sourceVisibility?: string | null;
94	}
95	
96	function serializeParam(value: string | Date | number | boolean): string {
97	  if (value instanceof Date) return value.toISOString();
98	  return String(value);
99	}
100	
101	function searchParamsFor(params: ListCurrentsParams): URLSearchParams {
102	  const search = new URLSearchParams();
103	  for (const [key, value] of Object.entries(params)) {
104	    if (value === undefined || value === null || value === "") continue;
105	    search.set(key, serializeParam(value));
106	  }
107	  return search;
108	}
109	
110	export function currentsBackendUrl(path: string, search?: string | URLSearchParams): string {
111	  const normalizedPath = path.startsWith("/") ? path : `/${path}`;
112	  const url = new URL(`${BACKEND}${normalizedPath}`);
113	  if (search instanceof URLSearchParams) {
114	    url.search = search.toString();
115	  } else if (search) {
116	    url.search = search.startsWith("?") ? search.slice(1) : search;
117	  }
118	  return url.toString();
119	}
120	
121	async function fetchJson<T>(
122	  path: string,
123	  search?: URLSearchParams,
124	  options: CurrentsFetchOptions = {},
125	): Promise<T> {
126	  const init: NextRequestInit = {
127	    method: "GET",
128	    headers: { accept: "application/json" },
129	  };
130	
131	  if (options.signal) init.signal = options.signal;
132	  if (options.next) init.next = options.next;
133	  if (options.cache) {
134	    init.cache = options.cache;
135	  } else if (!options.next) {
136	    init.cache = "no-store";
137	  }
138	
139	  const res = await fetch(currentsBackendUrl(path, search), init);
140	  if (!res.ok) {
141	    const detail = await res.text().catch(() => "");
142	    throw new Error(`Currents API ${res.status}${detail ? `: ${detail}` : ""}`);
143	  }
144	  return res.json() as Promise<T>;
145	}
146	
147	function normalizedVisibility(value: string | null | undefined): string | null {
148	  const normalized = (value ?? "").trim().toLowerCase().replace(/-/g, "_");
149	  return normalized || null;
150	}
151	
152	function publicUrlForVisibility(
153	  publicUrl: string | null | undefined,
154	  visibility: string | null | undefined,
155	): string | null {
156	  const trimmed = publicUrl?.trim();
157	  return trimmed && normalizedVisibility(visibility) === "org" ? trimmed : null;
158	}
159	
160	function sourceKind(citation: PublicCitation): string {
161	  return citation.source_kind.trim().toLowerCase();
162	}
163	
164	function citationNeedsMetadata(citation: CitationWire): boolean {
165	  return !(
166	    citation.conclusion_text?.trim() ||
167	    citation.conclusionText?.trim() ||
168	    citation.source_text?.trim()
169	  );
170	}
171	
172	function opinionHasInlineCitationMarkers(opinion: PublicOpinion): boolean {
173	  return /\[(?:\d+|C:[^\]\s]+)\]/.test(opinion.body_markdown);
174	}
175	
176	function sourceMetadata(source: SourceWire): CitationMetadata {
177	  return {
178	    conclusionText:
179	      source.conclusion_text?.trim() ||
180	      source.conclusionText?.trim() ||
181	      source.source_text?.trim() ||
182	      null,
183	    conclusionTitle:
184	      source.conclusion_title?.trim() || source.conclusionTitle?.trim() || null,
185	    publicUrl: source.public_url ?? source.publicUrl ?? null,
186	    sourceVisibility: source.source_visibility ?? source.visibility ?? null,
187	  };
188	}
189	
190	function normalizeCitation(
191	  citation: CitationWire,
192	  metadata: CitationMetadata | undefined,
193	): CitationWire {
194	  const visibility =
195	    metadata?.sourceVisibility ??
196	    citation.source_visibility ??
197	    citation.visibility ??
198	    null;
199	  const publicUrl = publicUrlForVisibility(
200	    metadata?.publicUrl ?? citation.public_url ?? citation.publicUrl ?? null,
201	    visibility,
202	  );
203	  const conclusionText =
204	    metadata?.conclusionText ??
205	    citation.conclusion_text ??
206	    citation.conclusionText ??
207	    citation.source_text ??
208	    null;
209	  const conclusionTitle =
210	    metadata?.conclusionTitle ??
211	    citation.conclusion_title ??
212	    citation.conclusionTitle ??
213	    null;
214	
215	  return {
216	    ...citation,
217	    conclusion_text: conclusionText,
218	    conclusion_title: conclusionTitle,
219	    public_url: publicUrl,
220	    source_visibility: normalizedVisibility(visibility),
221	  };
222	}
223	
224	function normalizeOpinion(
225	  opinion: PublicOpinion,
226	  metadataBySourceId: Map<string, CitationMetadata> = new Map(),
227	): PublicOpinion {
228	  return {
