317	async function counterConclusionMetadata(
318	  conclusionIds: string[],
319	): Promise<Map<string, CitationMetadata>> {
320	  const out = new Map<string, CitationMetadata>();
321	  if (!conclusionIds.length) return out;
322	  try {
323	    const { db } = await import("@/lib/db");
324	    const client = db as {
325	      conclusion: {
326	        findMany: (args: unknown) => Promise<
327	          {
328	            id: string;
329	            text: string | null;
330	            topicHint?: string | null;
331	            sources?: {
332	              upload?: {
333	                visibility?: string | null;
334	                deletedAt?: Date | string | null;
335	              } | null;
336	            }[];
337	          }[]
338	        >;
339	      };
340	      publishedConclusion: {
341	        findMany: (args: unknown) => Promise<
342	          {
343	            sourceConclusionId: string;
344	            slug: string;
345	            version: number;
346	            payloadJson: string;
347	          }[]
348	        >;
349	      };
350	    };
351	    const [conclusions, publications] = await Promise.all([
352	      client.conclusion.findMany({
353	        where: { id: { in: conclusionIds } },
354	        select: {
355	          id: true,
356	          text: true,
357	          topicHint: true,
358	          sources: {
359	            select: {
360	              upload: { select: { visibility: true, deletedAt: true } },
361	            },
362	          },
363	        },
364	      }),
365	      client.publishedConclusion.findMany({
366	        where: {
367	          kind: "CONCLUSION",
368	          sourceConclusionId: { in: conclusionIds },
369	        },
370	        orderBy: [{ publishedAt: "desc" }],
371	        select: {
372	          sourceConclusionId: true,
373	          slug: true,
374	          version: true,
375	          payloadJson: true,
376	        },
377	      }),
378	    ]);
379	    const latestPublication = new Map<string, (typeof publications)[number]>();
380	    for (const publication of publications) {
381	      if (!latestPublication.has(publication.sourceConclusionId)) {
382	        latestPublication.set(publication.sourceConclusionId, publication);
383	      }
384	    }
385	    for (const conclusion of conclusions) {
386	      const visibilities = (conclusion.sources ?? [])
387	        .map((source) => source.upload)
388	        .filter((upload) => upload && !upload.deletedAt)
389	        .map((upload) => normalizedVisibility(upload?.visibility));
390	      const visibility = visibilities.includes("org")
391	        ? "org"
392	        : visibilities.find(Boolean) ?? null;
393	      const publication = latestPublication.get(conclusion.id);
394	      const publicUrl =
395	        visibility === "org" && publication
396	          ? `/c/${encodeURIComponent(publication.slug)}/v/${publication.version}`
397	          : null;
398	      out.set(conclusion.id, {
399	        conclusionText: conclusion.text ?? null,
400	        conclusionTitle:
401	          titleFromPayload(publication?.payloadJson) ||
402	          titleFromText(conclusion.topicHint) ||
403	          titleFromText(conclusion.text),
404	        publicUrl,
405	        sourceVisibility: visibility,
406	      });
407	    }
408	  } catch {
409	    // No DB / no env: leave the map empty so the page still renders.
410	  }
411	  return out;
412	}
