415	async function reconciliationsForOpinions(
416	  opinions: PublicOpinion[],
417	): Promise<Map<string, PublicReconciliation>> {
418	  const result = new Map<string, PublicReconciliation>();
419	  if (!opinions.length) return result;
420	
421	  for (const opinion of opinions) {
422	    if (
423	      Array.isArray(opinion.uncertainty_notes) &&
424	      opinion.uncertainty_notes.includes(NO_COUNTER_UNCERTAINTY_TAG)
425	    ) {
426	      result.set(opinion.id, honestNoCounterReconciliation());
427	    }
428	  }
429	
430	  try {
431	    const { db } = await import("@/lib/db");
432	    const client = db as {
433	      opinionCitation: {
434	        findMany: (args: unknown) => Promise<
435	          {
436	            opinionId: string;
437	            sourceKind: string;
438	            conclusionId: string | null;
439	            claimId: string | null;
440	            quotedSpan: string;
441	            justificationMetadata: ReconciliationMetadata | null;
442	          }[]
443	        >;
444	      };
445	    };
446	    const rows = await client.opinionCitation.findMany({
447	      where: { opinionId: { in: opinions.map((opinion) => opinion.id) } },
448	      select: {
449	        opinionId: true,
450	        sourceKind: true,
451	        conclusionId: true,
452	        claimId: true,
453	        quotedSpan: true,
454	        justificationMetadata: true,
455	      },
456	    });
457	
458	    const counterConclusionIds = new Set<string>();
459	    for (const row of rows) {
460	      const metadata = row.justificationMetadata ?? {};
461	      if (metadata.role !== RECONCILIATION_ROLE) continue;
462	      if (row.sourceKind?.toLowerCase() === "conclusion" && row.conclusionId) {
463	        counterConclusionIds.add(row.conclusionId);
464	      }
465	    }
466	
467	    const conclusionMetadata = await counterConclusionMetadata(
468	      Array.from(counterConclusionIds),
469	    );
470	
471	    for (const row of rows) {
472	      const metadata = row.justificationMetadata ?? {};
473	      if (metadata.role !== RECONCILIATION_ROLE) continue;
474	      const sourceId =
475	        row.conclusionId ?? row.claimId ?? asString(metadata.counter_claim_id);
476	      if (!sourceId) continue;
477	      const counterMeta = conclusionMetadata.get(sourceId);
478	      result.set(
479	        row.opinionId,
480	        reconciliationFromMetadata(metadata, counterMeta, row.quotedSpan ?? ""),
481	      );
482	    }
483	  } catch {
484	    // Without DB access we fall back to whatever the no-counter tag implies.
485	  }
486	
487	  return result;
488	}
