490	function titleFromText(text: string | null | undefined): string | null {
491	  const normalized = text?.replace(/\s+/g, " ").trim();
492	  if (!normalized) return null;
493	  return normalized.length > 140 ? `${normalized.slice(0, 137)}...` : normalized;
494	}
495	
496	function titleFromPayload(payloadJson: unknown): string | null {
497	  if (typeof payloadJson !== "string" || !payloadJson.trim()) return null;
498	  try {
499	    const payload = JSON.parse(payloadJson) as { conclusionText?: unknown; title?: unknown };
500	    if (typeof payload.conclusionText === "string") {
501	      return titleFromText(payload.conclusionText);
502	    }
503	    if (typeof payload.title === "string") return titleFromText(payload.title);
504	  } catch {
505	    return null;
506	  }
507	  return null;
508	}
