721	export function passThroughHeaders(req: Request): Headers {
722	  const headers = new Headers();
723	  const userAgent = req.headers.get("user-agent");
724	  const contentType = req.headers.get("content-type");
725	  const ip = clientIpFor(req);
726	
727	  if (userAgent) headers.set("user-agent", userAgent);
728	  if (contentType) headers.set("content-type", contentType);
729	  if (ip !== "unknown") headers.set("x-forwarded-for", ip);
730	  headers.set("x-request-id", req.headers.get("x-request-id") || randomUUID());
731	
732	  return headers;
733	}
734	
735	function proxiedJsonHeaders(upstream: Response): Headers {
736	  const headers = new Headers();
737	  const contentType = upstream.headers.get("content-type");
738	  const cacheControl = upstream.headers.get("cache-control");
739	  const retryAfter = upstream.headers.get("retry-after");
740	
741	  if (contentType) headers.set("content-type", contentType);
742	  if (cacheControl) headers.set("cache-control", cacheControl);
743	  if (retryAfter) headers.set("retry-after", retryAfter);
744	  return headers;
745	}
746	
747	function proxiedSseHeaders(upstream: Response): Headers {
748	  const headers = new Headers();
749	  headers.set("content-type", upstream.headers.get("content-type") || "text/event-stream; charset=utf-8");
750	  headers.set("cache-control", "no-cache, no-transform");
751	  headers.set("connection", "keep-alive");
752	  headers.set("x-accel-buffering", "no");
753	  const retryAfter = upstream.headers.get("retry-after");
754	  if (retryAfter) headers.set("retry-after", retryAfter);
755	  return headers;
756	}
757	
758	function upstreamUnavailable(error: unknown): Response {
759	  const message = error instanceof Error ? error.message : "unknown upstream failure";
760	  return new Response(JSON.stringify({ error: "currents_upstream_unavailable", detail: message }), {
761	    status: 502,
762	    headers: { "content-type": "application/json" },
763	  });
764	}
765	
766	export function proxyResponse(upstream: Response): Response {
767	  return new Response(upstream.body, {
768	    status: upstream.status,
769	    statusText: upstream.statusText,
770	    headers: proxiedJsonHeaders(upstream),
771	  });
772	}
773	
774	export function proxySseResponse(upstream: Response): Response {
775	  if (!upstream.ok) return proxyResponse(upstream);
776	  return new Response(upstream.body, {
777	    status: upstream.status,
778	    statusText: upstream.statusText,
779	    headers: proxiedSseHeaders(upstream),
780	  });
781	}
