1	/**
2	 * Fire a GitHub `repository_dispatch` webhook so the
3	 * `noosphere-process-uploads.yml` workflow picks up a freshly-created
4	 * upload within seconds. This is the default "auto-process" path.
5	 *
6	 * Failures are *non-fatal*. If the token is missing, the target repo
7	 * is misconfigured, or GitHub is having a bad day, we swallow the
8	 * error and log it — the scheduled sweep on the same workflow will
9	 * catch the upload on its next 10-minute pass, so nothing gets lost.
10	 *
11	 * Required env (set on Vercel → Settings → Environment Variables):
12	 *
13	 *   GITHUB_DISPATCH_TOKEN   — a Personal Access Token (classic) with
14	 *                             the `repo` scope, or a fine-grained
15	 *                             PAT with `contents:write` on the
16	 *                             target repo. Without it this module
17	 *                             is a no-op.
18	 *
19	 *   GITHUB_DISPATCH_REPO    — "owner/repo" slug, e.g.
20	 *                             "mrquintin/mqtheseuswork". Defaults to
21	 *                             the published repo slug below so a
22	 *                             vanilla deploy works without config.
23	 *
24	 * The workflow itself tolerates running without this trigger — the
25	 * 10-minute cron gives us a belt-and-suspenders guarantee that
26	 * nothing stays in `queued_offline` for more than ~10 minutes.
27	 */
28	
29	const DEFAULT_REPO = "mrquintin/mqtheseuswork";
30	
31	export interface DispatchResult {
32	  /** True if we successfully hit GitHub's dispatch endpoint (204 No Content). */
33	  dispatched: boolean;
34	  /** Short human-readable note; fed back to the UI via processLog. */
35	  note: string;
36	  /** HTTP status code if we got a response; null on network error. */
37	  status: number | null;
38	}
39	
40	/** Check env without making a network call. Useful for UI gating. */
41	export function isAutoProcessConfigured(): boolean {
42	  return Boolean(process.env.GITHUB_DISPATCH_TOKEN);
43	}
44	
45	/**
46	 * POST to GitHub's repository_dispatch endpoint.
47	 *
48	 * Promise resolves with a `DispatchResult` — it never throws. The
49	 * caller should treat any `dispatched: false` outcome as "the cron
50	 * will pick it up" rather than a user-visible failure.
51	 */
52	export async function triggerNoosphereProcessing(
53	  uploadId: string,
54	  options: { organizationId?: string; withLlm?: boolean } = {},
55	): Promise<DispatchResult> {
56	  const token = process.env.GITHUB_DISPATCH_TOKEN;
57	  const repo = process.env.GITHUB_DISPATCH_REPO || DEFAULT_REPO;
58	
59	  if (!token) {
60	    return {
61	      dispatched: false,
62	      note:
63	        "Auto-processing skipped: GITHUB_DISPATCH_TOKEN not set on Vercel. " +
64	        "The 10-minute cron sweep will pick this upload up on its next pass.",
65	      status: null,
66	    };
67	  }
68	
69	  const url = `https://api.github.com/repos/${repo}/dispatches`;
70	  const body = {
71	    event_type: "process-upload",
72	    client_payload: {
73	      upload_id: uploadId,
74	      organization_id: options.organizationId || null,
75	      with_llm: options.withLlm ?? true,
76	      triggered_at: new Date().toISOString(),
77	    },
78	  };
79	
80	  try {
81	    const response = await fetch(url, {
82	      method: "POST",
83	      headers: {
84	        Accept: "application/vnd.github+json",
85	        Authorization: `Bearer ${token}`,
86	        "X-GitHub-Api-Version": "2022-11-28",
87	        "Content-Type": "application/json",
88	        "User-Agent": "theseus-codex/1.0 (+auto-process)",
89	      },
90	      body: JSON.stringify(body),
91	    });
92	
93	    // GitHub returns 204 on success. Any 2xx we treat as success.
94	    if (response.status >= 200 && response.status < 300) {
95	      return {
96	        dispatched: true,
97	        note: `Auto-processing dispatched to ${repo} (HTTP ${response.status}). Results appear in /conclusions within 1–2 minutes.`,
98	        status: response.status,
99	      };
100	    }
101	
102	    // Read the error body for diagnostics (GitHub returns JSON here).
103	    let errBody = "";
104	    try {
105	      const text = await response.text();
106	      errBody = text.slice(0, 300);
107	    } catch {
108	      errBody = "<unreadable>";
109	    }
110	    return {
111	      dispatched: false,
112	      note:
113	        `GitHub dispatch returned HTTP ${response.status}. ` +
114	        `Body: ${errBody}. ` +
115	        `The scheduled cron sweep will retry within 10 minutes.`,
116	      status: response.status,
117	    };
118	  } catch (err) {
119	    return {
120	      dispatched: false,
121	      note:
122	        `GitHub dispatch network error: ${err instanceof Error ? err.message : String(err)}. ` +
123	        `The scheduled cron sweep will retry within 10 minutes.`,
124	      status: null,
125	    };
126	  }
127	}
