22	  NOOSPHERE_UNAVAILABLE_MESSAGE,
23	} from "./pythonRuntime";
24	
25	const NOOSPHERE_PYTHON = process.env.NOOSPHERE_PYTHON || "python3";
26	/** Directory containing the `noosphere` Python package (parent of `noosphere/`). */
27	const NOOSPHERE_SRC_ROOT =
28	  process.env.NOOSPHERE_SRC_ROOT || join(process.cwd(), "..", "noosphere");
29	const OPENAI_API_KEY = process.env.OPENAI_API_KEY || "";
30	
31	async function appendLog(uploadId: string, chunk: string) {
32	  const prev = await db.upload.findUnique({
33	    where: { id: uploadId },
34	    select: { processLog: true },
35	  });
36	  const next = (prev?.processLog || "") + chunk;
37	  await db.upload.update({
38	    where: { id: uploadId },
39	    data: { processLog: next.slice(-200_000) },
40	  });
41	}
42	
43	async function extractText(filePath: string, mimeType: string, originalName: string): Promise<string | null> {
44	  if (
45	    mimeType === "text/plain" ||
46	    mimeType === "text/markdown" ||
47	    mimeType === "text/vtt" ||
48	    mimeType === "application/x-ndjson" ||
49	    originalName.match(/\.(txt|md|markdown|vtt|jsonl)$/i)
50	  ) {
51	    // `filePath` may be a real path (self-hosted) or a marker like
52	    // `inline:uuid.txt` (Vercel — see api/upload/route.ts). Only read from
53	    // disk when it looks like an actual path.
54	    if (filePath.startsWith("inline:")) return null;
55	    return readFile(filePath, "utf-8");
56	  }
57	  return null;
58	}
59	
60	async function transcribeAudio(filePath: string, originalName: string): Promise<string | null> {
61	  if (!OPENAI_API_KEY) return null;
62	  if (filePath.startsWith("inline:")) return null;
63	  try {
64	    const { default: OpenAI } = await import("openai");
65	    const openai = new OpenAI({ apiKey: OPENAI_API_KEY });
66	    const fileBuffer = await readFile(filePath);
67	    const file = new File([fileBuffer], originalName, { type: "audio/mpeg" });
68	    const transcription = await openai.audio.transcriptions.create({
69	      model: "whisper-1",
70	      file,
71	      response_format: "text",
72	    });
73	    return typeof transcription === "string"
74	      ? transcription
75	      : (transcription as { text?: string }).text || null;
76	  } catch {
77	    return null;
78	  }
79	}
