81	/**
82	 * Background job: mark processing → (try to) run CLI ingest + synthesize
83	 * → update counts / status. When Python isn't reachable we still persist
84	 * textContent to Postgres and set status to `queued_offline` so the user
85	 * can find the upload in the UI and run the CLI locally.
86	 */
87	export async function processUpload(uploadId: string): Promise<void> {
88	  const upload = await db.upload.findUnique({
89	    where: { id: uploadId },
90	    include: { founder: true },
91	  });
92	
93	  if (!upload) {
94	    console.error(`Upload ${uploadId} not found`);
95	    return;
96	  }
97	
98	  try {
99	    // APPEND to whatever processLog already exists (the upload handler
100	    // wrote an initial header + auto-process dispatch note before this
101	    // job started). Previously we overwrote the field, which nuked the
102	    // dispatch status message and made it look like auto-processing
103	    // wasn't configured. `appendLog` is read-then-write so it preserves
104	    // prior content.
105	    await appendLog(uploadId, "— Starting local Noosphere ingest —\n");
106	    await db.upload.update({
107	      where: { id: uploadId },
108	      data: { status: "processing" },
109	    });
110	
111	    let textContent = upload.textContent;
112	    if (!textContent) {
113	      const isAudio = upload.mimeType.startsWith("audio/");
114	      if (isAudio) {
115	        textContent = await transcribeAudio(upload.filePath, upload.originalName);
116	      } else {
117	        textContent = await extractText(upload.filePath, upload.mimeType, upload.originalName);
118	      }
119	      if (textContent) {
120	        await db.upload.update({ where: { id: uploadId }, data: { textContent } });
121	      }
122	    }
123	
124	    // ────────────────────────────────────────────────────────────────────
125	    // Serverless / Python-less hosts: don't even try to spawn. The upload
126	    // row is already persisted (textContent is in Postgres for text-like
127	    // files), so mark it as queued for offline processing and return.
128	    //
129	    // Two flavors:
130	    //   (a) auto-processing via GitHub Actions IS configured — a separate
131	    //       webhook + cron workflow will pick up `queued_offline` rows.
132	    //       We write a short "handed off" note pointing to the Actions
133	    //       run and return. The 10-min cron will turn this into
134	    //       `ingested` within minutes.
135	    //   (b) no auto-processing — fall back to the old "run it yourself"
136	    //       instructions.
137	    // ────────────────────────────────────────────────────────────────────
138	    if (isNoosphereLikelyUnavailable()) {
139	      const autoProcessRepo = process.env.GITHUB_DISPATCH_REPO || "mrquintin/mqtheseuswork";
140	      const autoProcessEnabled = Boolean(process.env.GITHUB_DISPATCH_TOKEN);
141	
142	      if (autoProcessEnabled) {
143	        await appendLog(
144	          uploadId,
145	          `\n— Python not available in this runtime —\n` +
146	            `Upload handed off to GitHub Actions. Watch the run live at\n` +
147	            `  https://github.com/${autoProcessRepo}/actions/workflows/noosphere-process-uploads.yml\n` +
148	            `Results (conclusions, contradictions, questions) appear at\n` +
149	            `/conclusions, /contradictions, /open-questions, /research\n` +
150	            `within 1–3 minutes. The 10-minute scheduled sweep also\n` +
151	            `picks up anything the immediate dispatch misses.\n`,
152	        );
153	        await db.upload.update({
154	          where: { id: uploadId },
155	          data: { status: "queued_offline", errorMessage: null },
156	        });
157	        await db.auditEvent.create({
158	          data: {
159	            organizationId: upload.organizationId,
160	            founderId: upload.founderId,
161	            uploadId: upload.id,
162	            action: "queued_offline",
163	            detail:
164	              "Upload stored; dispatched to GitHub Actions for " +
165	              "Noosphere processing.",
166	          },
167	        });
168	        return;
169	      }
170	
171	      // Fallback: no auto-processing secrets configured. Explain what to
172	      // set OR how to process locally.
173	      await appendLog(
174	        uploadId,
175	        `\n${NOOSPHERE_UNAVAILABLE_MESSAGE}\n\n` +
176	          `To enable automatic processing, set two repo secrets and one Vercel env var:\n` +
177	          `  GitHub → Settings → Secrets → Actions:   CODEX_DATABASE_URL (required), OPENAI_API_KEY (recommended)\n` +
178	          `  Vercel → Settings → Environment vars:    GITHUB_DISPATCH_TOKEN (required)\n` +
179	          `  See: docs/Auto_Processing_Setup.md for the 5-minute walkthrough.\n\n` +
180	          `Or process this upload right now from a machine with Noosphere installed:\n\n` +
181	          `    export DIRECT_URL="postgresql://postgres.<ref>:<pw>@...:5432/postgres"\n` +
182	          `    ./scripts/process-codex-upload.sh ${uploadId}             # naive mode\n` +
183	          `    ./scripts/process-codex-upload.sh ${uploadId} --with-llm  # full LLM\n` +
184	          `    ./scripts/process-codex-upload.sh --list                  # see queue\n\n` +
185	          `After processing, the extracted Conclusions show on /conclusions,\n` +
186	          `detected Contradictions on /contradictions, Open Questions on\n` +
187	          `/open-questions, and Research Suggestions on /research.\n`,
188	      );
189	      await db.upload.update({
190	        where: { id: uploadId },
191	        data: {
192	          status: "queued_offline",
193	          errorMessage: null,
194	        },
195	      });
196	      await db.auditEvent.create({
197	        data: {
198	          organizationId: upload.organizationId,
199	          founderId: upload.founderId,
200	          uploadId: upload.id,
201	          action: "queued_offline",
202	          detail:
203	            "Upload stored; Noosphere CLI unavailable in this runtime. " +
204	            "Process locally OR configure auto-processing.",
205	        },
206	      });
207	      return;
208	    }
209	
210	    await appendLog(uploadId, `\n$ ${NOOSPHERE_PYTHON} -m noosphere ingest ${upload.filePath}\n`);
211	
212	    const ingestArgs = ["-m", "noosphere", "ingest", upload.filePath];
213	    const ingest = await runNoospherePython(ingestArgs, {
214	      cwd: join(process.cwd(), ".."),
215	      envExtra: { PYTHONPATH: NOOSPHERE_SRC_ROOT },
216	      onChunk: (s) => appendLog(uploadId, s),
217	    });
218	
219	    // Belt-and-suspenders: even though we checked up front, a
220	    // misconfigured host could still surprise us with ENOENT. Handle it.
221	    if (ingest.skipped) {
222	      await appendLog(
223	        uploadId,
224	        `\n${NOOSPHERE_UNAVAILABLE_MESSAGE}\n` +
225	          `(Detected at spawn time. Marking upload as queued for offline ingest.)\n`,
226	      );
227	      await db.upload.update({
228	        where: { id: uploadId },
229	        data: { status: "queued_offline" },
230	      });
231	      return;
232	    }
233	
234	    if (ingest.code !== 0) {
235	      await db.upload.update({
236	        where: { id: uploadId },
237	        data: {
238	          status: "failed",
239	          errorMessage: `noosphere ingest exited ${ingest.code}. See process log.`,
240	        },
241	      });
242	      return;
243	    }
244	
245	    let artifactOk = false;
246	    try {
247	      const lines = ingest.out.trim().split("\n").filter(Boolean);
248	      const last = lines[lines.length - 1];
249	      if (last) {
250	        const j = JSON.parse(last) as { ok?: boolean };
251	        artifactOk = Boolean(j.ok);
252	      }
253	    } catch {
254	      artifactOk = ingest.out.includes('"ok": true');
255	    }
256	
257	    await appendLog(uploadId, `\n— Ingest finished (ok=${artifactOk}) —\n`);
258	    await appendLog(uploadId, `\n$ ${NOOSPHERE_PYTHON} -m noosphere synthesize\n`);
259	
260	    const synth = await runNoospherePython(["-m", "noosphere", "synthesize"], {
261	      cwd: join(process.cwd(), ".."),
262	      envExtra: { PYTHONPATH: NOOSPHERE_SRC_ROOT },
263	      onChunk: (s) => appendLog(uploadId, s),
264	    });
265	
266	    if (synth.skipped) {
267	      await appendLog(
268	        uploadId,
269	        `\n[warn] synthesize skipped — Noosphere CLI disappeared between ingest and synthesize. ` +
270	          `Upload is ingested but unsynthesized.\n`,
271	      );
272	    } else if (synth.code !== 0) {
273	      await appendLog(uploadId, `\n[warn] synthesize exited ${synth.code}\n`);
274	    }
275	
276	    await db.upload.update({
277	      where: { id: uploadId },
278	      data: {
279	        status: "ingested",
280	        claimsCount: artifactOk ? 1 : 0,
281	        principleCount: 0,
282	        methodCount: 0,
283	        substCount: 0,
284	      },
285	    });
286	
287	    await db.auditEvent.create({
288	      data: {
289	        organizationId: upload.organizationId,
290	        founderId: upload.founderId,
291	        uploadId: upload.id,
292	        action: "ingest",
293	        detail: "noosphere ingest + synthesize completed",
294	      },
295	    });
296	  } catch (err) {
297	    console.error(`Processing upload ${uploadId} failed:`, err);
298	    await db.upload.update({
299	      where: { id: uploadId },
300	      data: {
301	        status: "failed",
302	        errorMessage: err instanceof Error ? err.message : "Unknown error",
303	      },
304	    });
305	  }
306	}
