2	 * Live status of the auto-processing pipeline.
3	 *
4	 * The dashboard calls this to decide whether to show a "Setup
5	 * auto-processing" banner vs. a "Auto-processing active" pill.
6	 *
7	 * Returns a small JSON blob:
8	 * {
9	 *   "vercel": {
10	 *     "github_dispatch_token": boolean,   // GITHUB_DISPATCH_TOKEN on Vercel
11	 *     "github_dispatch_repo": string,     // effective repo slug
12	 *     "openai_key": boolean,              // OPENAI_API_KEY for Whisper
13	 *   },
14	 *   "github": {
15	 *     // We can't verify GitHub secrets from Vercel — only the user's
16	 *     // own view of Actions UI can do that. But we include hints.
17	 *     "workflow_url": "https://github.com/<repo>/actions/workflows/…",
18	 *     "known_to_fail_without": ["CODEX_DATABASE_URL"],
19	 *   },
20	 *   "configured": boolean,                // true if the webhook path works
21	 *   "summary": string,                    // short human-readable line
22	 * }
23	 *
24	 * Requires the same auth as the rest of /api — session cookie OR API key.
25	 */
