29	export async function GET(req: Request) {
30	  const founder = await getFounderFromAuth(req);
31	  if (!founder) {
32	    return NextResponse.json({ error: "Not authenticated" }, { status: 401 });
33	  }
34	
35	  const hasToken = Boolean(process.env.GITHUB_DISPATCH_TOKEN);
36	  const hasOpenAI = Boolean(process.env.OPENAI_API_KEY);
37	  const repo = process.env.GITHUB_DISPATCH_REPO || "mrquintin/mqtheseuswork";
38	  const workflowUrl = `https://github.com/${repo}/actions/workflows/noosphere-process-uploads.yml`;
39	
40	  const configured = hasToken;
41	  const summary = hasToken
42	    ? `Webhook dispatch active → ${repo} · ` +
43	      (hasOpenAI ? "LLM mode (OpenAI)" : "Naive mode (set OPENAI_API_KEY for LLM)")
44	    : "Auto-processing not configured — set GITHUB_DISPATCH_TOKEN on Vercel + CODEX_DATABASE_URL on GitHub";
45	
46	  return NextResponse.json({
47	    vercel: {
48	      github_dispatch_token: hasToken,
49	      github_dispatch_repo: repo,
50	      openai_key: hasOpenAI,
51	    },
52	    github: {
53	      workflow_url: workflowUrl,
54	      known_to_fail_without: ["CODEX_DATABASE_URL"],
