  spanCount: number;
  errorCount: number;
  rootName: string;
  status: "ok" | "error" | "in_flight";
};

export type MethodMetricRow = {
  method: string;
  count: number;
  errorCount: number;
  errorRate: number;
  p50Ms: number;
  p95Ms: number;
